declare void @add_byval_callee(ptr)

define void @add_byval(ptr %in) {
  %tmp = bitcast ptr @add_byval_callee to ptr
  call void %tmp(ptr byval(i64) %in)
  ret void
}

%Foo = type { i64 }

declare i64 @foo(ptr byval(%Foo))

define i64 @bar(i64 %0) {
  %2 = tail call i64 @foo(i64 %0)
  ret i64 %2
}

%Foo = type { i64 }

declare i64 @bar(i64)

define i64 @qux(ptr byval(%Foo) %qux) {
  %1 = tail call i64 @bar(ptr byval(%Foo) %qux)
  ret i64 %1
}
